// ESP32 Dual-Core RTOS Hub
// ========================
// Demonstrates FreeRTOS dual-core task execution:
// - Core 0: Sensor task reads button + potentiometer, sends via queue
// - Core 1: Control task receives data, drives LEDs, prints telemetry
//
// Circuit:
//   GPIO15 <- Pushbutton -> GND  (INPUT_PULLUP)
//   GPIO34 <- Potentiometer SIG  (ADC, input-only pin)
//   GPIO2  -> 220R -> Green LED -> GND  (ADC threshold indicator)
//   GPIO4  -> 220R -> Red LED -> GND    (Button press indicator)
//
// ESP32-only features used:
//   xTaskCreatePinnedToCore(), analogReadResolution(12), GPIO34 input-only

#include <Arduino.h>

// --- Pin Assignments ---
const int BUTTON_PIN  = 15;   // Pushbutton with internal pull-up
const int ADC_PIN     = 34;   // Potentiometer (input-only GPIO)
const int LED_GREEN   = 2;    // ADC threshold indicator
const int LED_RED     = 4;    // Button press indicator

// --- RTOS handles ---
QueueHandle_t sensorQueue;

struct SensorMsg {
  uint16_t adc;       // 12-bit ADC reading (0-4095)
  bool     pressed;   // true when button is held
  uint32_t timestamp; // millis() at sample time
};

// ---- Task pinned to Core 0: Read sensors ----
void sensorTask(void* /*param*/) {
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  Serial.println("[Core 0] Sensor task started");

  for (;;) {
    SensorMsg msg;
    msg.adc       = analogRead(ADC_PIN);
    msg.pressed   = (digitalRead(BUTTON_PIN) == LOW);
    msg.timestamp = millis();

    // Overwrite (latest-value) semantics: never blocks
    xQueueOverwrite(sensorQueue, &msg);
    vTaskDelay(pdMS_TO_TICKS(50));  // 20 Hz sample rate
  }
}

// ---- Task pinned to Core 1: Control outputs ----
void controlTask(void* /*param*/) {
  pinMode(LED_GREEN, OUTPUT);
  pinMode(LED_RED, OUTPUT);
  Serial.println("[Core 1] Control task started");

  SensorMsg msg = {};
  uint32_t lastPrint = 0;

  for (;;) {
    if (xQueueReceive(sensorQueue, &msg, pdMS_TO_TICKS(100)) == pdTRUE) {
      // Green LED: on when potentiometer above mid-range
      bool adcHigh = (msg.adc > 2048);
      digitalWrite(LED_GREEN, adcHigh ? HIGH : LOW);

      // Red LED: on while button pressed
      digitalWrite(LED_RED, msg.pressed ? HIGH : LOW);

      // Throttled serial output (~4 Hz)
      if (msg.timestamp - lastPrint >= 250) {
        lastPrint = msg.timestamp;
        Serial.print("[core ");
        Serial.print(xPortGetCoreID());
        Serial.print("] t=");
        Serial.print(msg.timestamp);
        Serial.print("  adc=");
        Serial.print(msg.adc);
        Serial.print("  btn=");
        Serial.print(msg.pressed ? "DOWN" : "UP");
        Serial.print("  green=");
        Serial.print(adcHigh ? "ON" : "OFF");
        Serial.print("  red=");
        Serial.println(msg.pressed ? "ON" : "OFF");
      }
    }
  }
}

void setup() {
  Serial.begin(115200);
  delay(300);

  Serial.println("===========================");
  Serial.println("  ESP32 Dual-Core RTOS Hub");
  Serial.println("===========================");
  Serial.println();

  // 12-bit ADC for full ESP32 range
  analogReadResolution(12);

  // Create 1-element queue (latest value)
  sensorQueue = xQueueCreate(1, sizeof(SensorMsg));
  if (!sensorQueue) {
    Serial.println("ERROR: Failed to create queue!");
    while (true) { delay(1000); }
  }

  // Pin tasks to separate cores
  xTaskCreatePinnedToCore(sensorTask,  "sensor",  4096, nullptr, 1, nullptr, 0);
  xTaskCreatePinnedToCore(controlTask, "control", 4096, nullptr, 1, nullptr, 1);

  Serial.println("Tasks created. Main loop idle.");
  Serial.println("---");
}

void loop() {
  // Main Arduino loop intentionally idle.
  // All real work happens in the two RTOS tasks.
  vTaskDelay(pdMS_TO_TICKS(1000));
}
